file.content:
.game-container {
    text-align: center;
    max-width: 600px;
    width: 100%;
    height: 100dvh;
    padding: 10px clamp(10px, 3vw, 20px);
    display: none;
    flex-direction: column;
    justify-content: center;
    gap: clamp(8px, 4vw, 20px);
    position: relative;
    overflow: hidden;
    touch-action: none;
    overscroll-behavior: none;
}

.back-btn {
    position: absolute;
    top: calc(10px + env(safe-area-inset-top));
    left: clamp(10px, 3vw, 20px);
    background: #141414;
    border: 3px solid #000;
    border-radius: 35%;
    width: clamp(30px, 6vw, 40px);
    height: clamp(30px, 6vw, 40px);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: clamp(16px, 4vw, 24px);
    z-index: 10;
    color: rgba(255, 255, 255, 0.8);
    padding-bottom: 2px;
}

.game-coins-display {
    position: absolute;
    top: calc(10px + env(safe-area-inset-top));
    left: 50%;
    transform: translateX(-50%);
    z-index: 10;
    padding: 2px clamp(12px, 2.5vw, 20px);
    box-shadow: none;

    .coin-icon {
        width: clamp(24px, 5vw, 32px);
        height: clamp(24px, 5vw, 32px);
    }
}

.game-info-btn {
    position: absolute;
    top: calc(10px + env(safe-area-inset-top));
    right: clamp(10px, 3vw, 20px);
    background: #141414;
    border: 3px solid #000;
    border-radius: 35%;
    width: clamp(30px, 6vw, 40px);
    height: clamp(30px, 6vw, 40px);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: clamp(16px, 4vw, 24px);
    font-family: Nunito;
    font-weight: 900;
    z-index: 10;
    color: rgba(255, 255, 255, 0.8);
}

.top-spacer {
    flex: 1 999 0;
    min-height: 0;
    justify-content: center;
    display: flex;
    align-items: center;
}

.level-text {
    margin: 0;
    color: rgba(255, 255, 255, 0.5);
    font-family: Nunito;
    font-size: 32px;
    font-style: normal;
    font-weight: 900;
    line-height: normal;
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 100;
    pointer-events: none;
    width: 90%;
}

#levelSolvedSvg {
    position: relative;
}

#levelFailedSvg {
    position: absolute;
    width: 100%;
    left: 0;
    top: 0;
}

#failReasonText {
    position: absolute;
    width: 100%;
    left: 0;
    top: 50px;
}

#levelSolvedSvg.animate {
    animation: levelSolvedBounce 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

#levelFailedSvg.animate {
    animation: levelFailedBounce 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes levelSolvedBounce {
    0% {
        opacity: 0;
        transform: scale(0.3);
    }
    50% {
        opacity: 1;
        transform: scale(1.15);
    }
    70% {
        transform: scale(0.9);
    }
    85% {
        transform: scale(1.05);
    }
    100% {
        transform: scale(1);
        opacity: 1;
    }
}

@keyframes levelFailedBounce {
    0% {
        opacity: 0;
        transform: scale(0.3);
    }
    50% {
        opacity: 1;
        transform: scale(1.15);
    }
    70% {
        transform: scale(0.9);
    }
    85% {
        transform: scale(1.05);
    }
    100% {
        transform: scale(1);
        opacity: 1;
    }
}

.game-info {
    display: flex;
    gap: clamp(10px, 3vw, 20px);
    justify-content: center;
    align-items: center;
    flex-shrink: 0;
    width: 100%;
    align-items: stretch;
    min-height: 80px;
}

.goals-container,
.moves-container,
.board-upgrades-container {
    position: relative;
    border-radius: 24px;
    border: 3px solid #000;
    background: #141414;

    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
}

.goals-container .label,
.moves-container .label,
.board-upgrades-container .label {
    position: absolute;
    top: -15px;
    left: 50%;
    transform: translateX(-50%);
    font-family: Nunito;
    font-size: 22px;
