.game-board {
    display: grid;
    grid-template-columns: repeat(8, 1fr);
    grid-template-rows: repeat(8, 1fr);
    gap: clamp(1px, 0.7vw, 3px);
    border: 3px solid #000;
    background: #141414;
    padding: clamp(6px, 3vw, 15px);
    border-radius: 24px;
    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
    margin: 0 auto;
    flex-shrink: 1;
    flex-grow: 0;
    max-height: 50dvh;
    touch-action: none;
    overscroll-behavior: none;
    transition: opacity 0.3s ease;
}

.game-board.level-ended {
    opacity: 0.5;
}

.gem {
    aspect-ratio: 1;
    border-radius: 20%;
    cursor: pointer;
    position: relative;
    transition:
        transform 0.3s ease,
        opacity 150ms ease,
        background-color 0.3s ease,
        box-shadow 0.3s ease,
        filter 0.3s ease,
        outline-color 0.3s ease;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
    font-family: Nunito;
    font-size: clamp(16px, 3vw, 24px);
    font-weight: 900;
    color: #45413d;
    container-type: inline-size;
    container-name: card;
    padding-bottom: 2px;
    outline-color: rgba(0, 0, 0, 0);

    -webkit-tap-highlight-color: transparent;
}

.gem > * {
    pointer-events: none;
}

.gem.swap-dimmed {
    opacity: 0.6;
    pointer-events: none;
}

.gem.dragging {
    z-index: 10;
    scale: 0.95;
    opacity: 0.8 !important;
}

/* Target tile during drag preview — not the source being dragged.
   Higher z-index so the scaled-up ring peeks above neighbor tiles. */
.gem.preview:not(.dragging),
.gem.pending-preview:not(.dragging) {
    scale: 1.1;
    z-index: 500;
    box-shadow:
        0 -3px 0 0 rgba(0, 0, 0, 0.25) inset,
        0 0 0 3px rgba(255, 255, 255, 0.95),
        0 0 14px 4px rgba(255, 255, 255, 0.55);
}

/* 1-tile boundary detent: short ring pulse when drag crosses out of the
   adjacent zone on a teleport/freeswap tile. Trains the boundary feel. */
.gem.detent-crossed::before {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    border: 3px solid rgba(255, 220, 100, 0.9);
    pointer-events: none;
    animation: detent-pulse 260ms ease-out forwards;
}

@keyframes detent-pulse {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    100% {
        transform: scale(1.6);
        opacity: 0;
    }
}

